isVisible:
{{
  (() => {
    if (ModalInputRiskStatus.selectedOptionValue !== "At Risk") return false;

    const data = Array.isArray(GetCurrentRiskStatus.data) ? 
                 GetCurrentRiskStatus.data : [];

    const oppHistory = data.filter(item => 
      item.opp_id === Renewal_List.selectedRow?.opportunity_id
    ).sort((a, b) => new Date(b.submit_timestamp) - new Date(a.submit_timestamp));

    const lastAtRisk = oppHistory.find(item => 
      item.risk_status === "At Risk" && item.risk_label
    );

    return !!lastAtRisk;
  })()
}}

text:
{{
  (() => {
    if (ModalInputRiskStatus.selectedOptionValue !== "At Risk") return "";

    const data = Array.isArray(GetCurrentRiskStatus.data) ? 
                 GetCurrentRiskStatus.data : [];

    const oppHistory = data.filter(item => 
      item.opp_id === Renewal_List.selectedRow?.opportunity_id
    ).sort((a, b) => new Date(b.submit_timestamp) - new Date(a.submit_timestamp));

    const lastAtRisk = oppHistory.find(item => 
      item.risk_status === "At Risk" && item.risk_label
    );

    if (lastAtRisk) {
      const categoryName = RiskCategory.sourceData.find(
        cat => cat.code === lastAtRisk.risk_label
      )?.name || lastAtRisk.risk_label;

      return `ℹ️ Automatisch vorausgefüllt mit letzter Kategorie: "${categoryName}" vom ${moment(lastAtRisk.submit_timestamp).format('DD.MM.YY')}. Bei Bedarf ändern.`;
    }

    return "";
  })()
}}
